SELECT
    id, cert_no, valid_until, inspect_year, inspect_time, inspect_item,
    fee, location, vehicle_id, inspector, sender, status,
    remark, create_time, update_time
FROM vehicle_inspection


        AND id = #{id}


        AND vehicle_id = #{vehicleId}


        AND cert_no LIKE CONCAT('%', #{certNo}, '%')


        AND status = #{status}


ORDER BY inspect_time DESC

